@Base.kwdef struct SimulatedTraits <: Phylogenetic
    numtraits = 1000
    variance_distribution = Exponential(1.0)
    truncated_dims = 8
end
outdim(st::SimulatedTraits, ::Union{Type{Bee}, Type{Plant}}) = st.truncated_dims

function getfeatures(st::SimulatedTraits, data)
    dict = Dict()

    species = vcat(bees(data), plants(data))

    bee_tree, plant_tree = parsenewick.(get_newick())
    df = vcat(_simulated_trait_features(st, bee_tree), _simulated_trait_features(st,plant_tree))
    
    for r in eachrow(df)
        k = species[findfirst(s->s.name==r.species, species)]
        merge!(dict, Dict(k=>[x for x in r[2:end]]))
    end
    return dict
end

